     1→"use client";
     2→
     3→import { useState } from "react";
     4→
     5→interface FormValues {
     6→  name: string;
     7→  email: string;
     8→  subject: string;
     9→  message: string;
    10→}
    11→
    12→interface FormErrors {
    13→  name?: string;
    14→  email?: string;
    15→  subject?: string;
    16→  message?: string;
    17→}
    18→
    19→const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    20→
    21→function validate(values: FormValues): FormErrors {
    22→  const errors: FormErrors = {};
    23→  if (!values.name.trim()) {
    24→    errors.name = "Name is required.";
    25→  }
    26→  if (!values.email.trim()) {
    27→    errors.email = "Email is required.";
    28→  } else if (!EMAIL_REGEX.test(values.email)) {
    29→    errors.email = "Please enter a valid email address.";
    30→  }
    31→  if (!values.subject.trim()) {
    32→    errors.subject = "Subject is required.";
    33→  }
    34→  if (!values.message.trim()) {
    35→    errors.message = "Message is required.";
    36→  }
    37→  return errors;
    38→}
    39→
    40→export function ContactForm() {
    41→  const [values, setValues] = useState<FormValues>({
    42→    name: "",
    43→    email: "",
    44→    subject: "",
    45→    message: "",
    46→  });
    47→  const [touched, setTouched] = useState<Record<string, boolean>>({});
    48→  const [submitted, setSubmitted] = useState(false);
    49→
    50→  const errors = validate(values);
    51→  const isValid = Object.keys(errors).length === 0;
    52→
    53→  function handleChange(
    54→    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>,
    55→  ) {
    56→    const { name, value } = e.target;
    57→    setValues((prev) => ({ ...prev, [name]: value }));
    58→  }
    59→
    60→  function handleBlur(
    61→    e: React.FocusEvent<HTMLInputElement | HTMLTextAreaElement>,
    62→  ) {
    63→    const { name } = e.target;
    64→    setTouched((prev) => ({ ...prev, [name]: true }));
    65→  }
    66→
    67→  function handleSubmit(e: React.FormEvent<HTMLFormElement>) {
    68→    e.preventDefault();
    69→    setTouched({ name: true, email: true, subject: true, message: true });
    70→    // TODO: wire to contact form API (e.g. SendGrid, Resend, or internal endpoint)
    71→    if (isValid) {
    72→      setSubmitted(true);
    73→    }
    74→  }
    75→
    76→  const inputClass =
    77→    "w-full rounded-[8px] border border-amber/40 bg-white/80 px-4 py-3 font-body text-sm text-cafe-noir placeholder-cafe-noir/40 outline-none transition-colors focus:border-kombu-green";
    78→  const errorClass = "mt-1 font-body text-xs text-red-600";
    79→
    80→  if (submitted) {
    81→    return (
    82→      <div
    83→        role="status"
    84→        className="flex flex-col items-center justify-center rounded-[16px] border border-amber/20 bg-white/70 p-10 shadow-sm text-center"
    85→      >
    86→        <div className="mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-kombu-green/10">
    87→          <svg
    88→            viewBox="0 0 24 24"
    89→            fill="none"
    90→            stroke="currentColor"
    91→            strokeWidth={2}
    92→            strokeLinecap="round"
    93→            strokeLinejoin="round"
    94→            className="h-6 w-6 text-kombu-green"
    95→            aria-hidden="true"
    96→          >
    97→            <polyline points="20 6 9 17 4 12" />
    98→          </svg>
    99→        </div>
   100→        <h2 className="mb-2 font-heading text-2xl font-semibold text-cafe-noir">
   101→          Message Sent
   102→        </h2>
   103→        <p className="font-body text-base leading-relaxed text-cafe-noir/70">
   104→          Thank you for your message. We will be in touch soon.
   105→        </p>
   106→      </div>
   107→    );
   108→  }
   109→
   110→  return (
   111→    <div className="rounded-[16px] border border-amber/20 bg-white/70 p-6 shadow-sm">
   112→      <h2 className="mb-6 font-heading text-2xl font-semibold text-cafe-noir">
   113→        Send a Message
   114→      </h2>
   115→      <form onSubmit={handleSubmit} noValidate>
   116→        <div className="mb-4">
   117→          <label
   118→            htmlFor="name"
   119→            className="mb-1 block font-body text-sm font-medium text-cafe-noir"
   120→          >
   121→            Name <span aria-hidden="true">*</span>
   122→          </label>
   123→          <input
   124→            id="name"
   125→            name="name"
   126→            type="text"
   127→            autoComplete="name"
   128→            required
   129→            value={values.name}
   130→            onChange={handleChange}
   131→            onBlur={handleBlur}
   132→            placeholder="Your full name"
   133→            aria-describedby={
   134→              touched.name && errors.name ? "name-error" : undefined
   135→            }
   136→            aria-invalid={touched.name && !!errors.name}
   137→            className={inputClass}
   138→          />
   139→          {touched.name && errors.name && (
   140→            <p id="name-error" className={errorClass} role="alert">
   141→              {errors.name}
   142→            </p>
   143→          )}
   144→        </div>
   145→
   146→        <div className="mb-4">
   147→          <label
   148→            htmlFor="email"
   149→            className="mb-1 block font-body text-sm font-medium text-cafe-noir"
   150→          >
   151→            Email <span aria-hidden="true">*</span>
   152→          </label>
   153→          <input
   154→            id="email"
   155→            name="email"
   156→            type="email"
   157→            autoComplete="email"
   158→            required
   159→            value={values.email}
   160→            onChange={handleChange}
   161→            onBlur={handleBlur}
   162→            placeholder="you@example.com"
   163→            aria-describedby={
   164→              touched.email && errors.email ? "email-error" : undefined
   165→            }
   166→            aria-invalid={touched.email && !!errors.email}
   167→            className={inputClass}
   168→          />
   169→          {touched.email && errors.email && (
   170→            <p id="email-error" className={errorClass} role="alert">
   171→              {errors.email}
   172→            </p>
   173→          )}
   174→        </div>
   175→
   176→        <div className="mb-4">
   177→          <label
   178→            htmlFor="subject"
   179→            className="mb-1 block font-body text-sm font-medium text-cafe-noir"
   180→          >
   181→            Subject <span aria-hidden="true">*</span>
   182→          </label>
   183→          <input
   184→            id="subject"
   185→            name="subject"
   186→            type="text"
   187→            required
   188→            value={values.subject}
   189→            onChange={handleChange}
   190→            onBlur={handleBlur}
   191→            placeholder="What is this about?"
   192→            aria-describedby={
   193→              touched.subject && errors.subject ? "subject-error" : undefined
   194→            }
   195→            aria-invalid={touched.subject && !!errors.subject}
   196→            className={inputClass}
   197→          />
   198→          {touched.subject && errors.subject && (
   199→            <p id="subject-error" className={errorClass} role="alert">
   200→              {errors.subject}
   201→            </p>
   202→          )}
   203→        </div>
   204→
   205→        <div className="mb-6">
   206→          <label
   207→            htmlFor="message"
   208→            className="mb-1 block font-body text-sm font-medium text-cafe-noir"
   209→          >
   210→            Message <span aria-hidden="true">*</span>
   211→          </label>
   212→          <textarea
   213→            id="message"
   214→            name="message"
   215→            required
   216→            rows={5}
   217→            value={values.message}
   218→            onChange={handleChange}
   219→            onBlur={handleBlur}
