    21→interface MobileMenuProps {
    22→  isOpen: boolean;
    23→  onClose: () => void;
    24→  returnFocusRef?: RefObject<HTMLButtonElement | null>;
    25→}
    26→
    27→export function MobileMenu({
    28→  isOpen,
    29→  onClose,
    30→  returnFocusRef,
    31→}: MobileMenuProps) {
    32→  const pathname = usePathname();
    33→  const closeButtonRef = useRef<HTMLButtonElement>(null);
    34→  const panelRef = useRef<HTMLDivElement>(null);
    35→
    36→  const toggleSearch = useUiStore((s) => s.toggleSearch);
    37→  const openAuthModal = useUiStore((s) => s.openAuthModal);
    38→  const itemCount = useCartStore((s) => s.itemCount);
    39→
    40→  // Stable ref so the route-change effect doesn't need onClose in its dep array
    41→  const onCloseRef = useRef(onClose);
    42→  useEffect(() => {
    43→    onCloseRef.current = onClose;
    44→  }, [onClose]);
    45→
    46→  // Close on route change — pathname is the intentional trigger
    47→  // biome-ignore lint/correctness/useExhaustiveDependencies: onClose is accessed via stable ref
    48→  useEffect(() => {
    49→    onCloseRef.current();
    50→  }, [pathname]);
    51→
    52→  // Focus close button when opened; restore focus to hamburger when closed
    53→  useEffect(() => {
    54→    if (isOpen) {
    55→      closeButtonRef.current?.focus();
    56→    } else {
    57→      returnFocusRef?.current?.focus();
    58→    }
    59→  }, [isOpen, returnFocusRef]);
    60→
    61→  // Escape key to close
    62→  useEffect(() => {
    63→    if (!isOpen) return;
    64→
    65→    function handleKeyDown(e: KeyboardEvent) {
    66→      if (e.key === "Escape") onClose();
    67→    }
    68→
    69→    document.addEventListener("keydown", handleKeyDown);
    70→    return () => document.removeEventListener("keydown", handleKeyDown);
    71→  }, [isOpen, onClose]);
    72→
    73→  // Trap focus inside panel
    74→  useEffect(() => {
    75→    if (!isOpen || !panelRef.current) return;
    76→
    77→    const panel = panelRef.current;
    78→    const focusable = panel.querySelectorAll<HTMLElement>(
    79→      'a[href], button:not([disabled]), [tabindex]:not([tabindex="-1"])',
    80→    );
    81→    const first = focusable[0];
    82→    const last = focusable[focusable.length - 1];
    83→
    84→    function handleTab(e: KeyboardEvent) {
    85→      if (e.key !== "Tab") return;
    86→      if (e.shiftKey) {
    87→        if (document.activeElement === first) {
    88→          e.preventDefault();
    89→          last?.focus();
    90→        }
    91→      } else {
    92→        if (document.activeElement === last) {
    93→          e.preventDefault();
    94→          first?.focus();
    95→        }
    96→      }
    97→    }
    98→
    99→    document.addEventListener("keydown", handleTab);
   100→    return () => document.removeEventListener("keydown", handleTab);
   101→  }, [isOpen]);
   102→
   103→  // Prevent body scroll when open
   104→  useEffect(() => {
   105→    if (isOpen) {
   106→      document.body.style.overflow = "hidden";
   107→    } else {
   108→      document.body.style.overflow = "";
   109→    }
   110→    return () => {
   111→      document.body.style.overflow = "";
   112→    };
   113→  }, [isOpen]);
   114→
   115→  function handleSearchClick() {
   116→    toggleSearch();
   117→    onClose();
   118→  }
   119→
   120→  function handleAccountClick() {
   121→    openAuthModal();
   122→    onClose();
   123→  }
   124→
   125→  return (
   126→    <>
   127→      {/* Backdrop */}
   128→      <div
   129→        aria-hidden="true"
   130→        className={[
   131→          "fixed inset-0 z-40 bg-kombu-green/60 backdrop-blur-sm transition-opacity duration-300",
   132→          isOpen ? "opacity-100" : "pointer-events-none opacity-0",
   133→        ].join(" ")}
   134→        onClick={onClose}
   135→      />
   136→
   137→      {/* Panel */}
   138→      <div
   139→        ref={panelRef}
   140→        role="dialog"
   141→        aria-modal="true"
   142→        aria-label="Navigation menu"
   143→        inert={!isOpen}
   144→        className={[
   145→          "fixed inset-0 z-50 flex flex-col bg-kombu-green/95 backdrop-blur-[24px] backdrop-saturate-[200%] transition-all duration-300",
   146→          isOpen
   147→            ? "translate-y-0 opacity-100"
   148→            : "-translate-y-4 opacity-0 pointer-events-none",
   149→        ].join(" ")}
   150→      >
   151→        {/* Header */}
   152→        <div className="flex items-center justify-between border-b border-moss-green/20 px-6 py-5">
   153→          <Link
   154→            href="/"
   155→            onClick={onClose}
   156→            className="font-heading text-xl font-semibold text-bone"
   157→          >
   158→            Riverine Ranch
   159→          </Link>
   160→          <button
   161→            ref={closeButtonRef}
   162→            type="button"
   163→            onClick={onClose}
   164→            aria-label="Close navigation menu"
   165→            className="rounded-full p-2 text-bone transition-colors duration-150 hover:bg-moss-green/20 hover:text-amber"
   166→          >
   167→            <X size={22} aria-hidden="true" />
   168→          </button>
   169→        </div>
   170→
   171→        {/* Nav links */}
   172→        <nav
   173→          aria-label="Mobile primary navigation"
   174→          className="flex-1 overflow-y-auto px-6 py-8"
   175→        >
   176→          <ul className="flex flex-col gap-1">
   177→            {navLinks.map(({ label, href }) => (
   178→              <li key={href}>
   179→                <Link
   180→                  href={href}
   181→                  onClick={onClose}
   182→                  className="block rounded-lg px-4 py-3 font-body text-lg font-medium text-bone transition-colors duration-150 hover:bg-moss-green/20 hover:text-amber"
   183→                >
   184→                  {label}
   185→                </Link>
   186→              </li>
   187→            ))}
   188→          </ul>
   189→        </nav>
   190→
   191→        {/* Action row */}
   192→        <div className="border-t border-moss-green/20 px-6 py-6">
   193→          <div className="flex items-center gap-3">
   194→            <button
   195→              type="button"
   196→              onClick={handleSearchClick}
   197→              aria-label="Search"
   198→              className="flex flex-1 items-center gap-3 rounded-lg px-4 py-3 text-bone transition-colors duration-150 hover:bg-moss-green/20 hover:text-amber"
   199→            >
