   202→            </button>
   203→
   204→            <button
   205→              type="button"
   206→              onClick={handleAccountClick}
   207→              aria-label="Account"
   208→              className="flex flex-1 items-center gap-3 rounded-lg px-4 py-3 text-bone transition-colors duration-150 hover:bg-moss-green/20 hover:text-amber"
   209→            >
   210→              <User size={22} />
   211→              <span className="font-body text-sm">Account</span>
   212→            </button>
   213→
   214→            <Link
   215→              href="/cart"
   216→              onClick={onClose}
   217→              aria-label={itemCount > 0 ? `Cart, ${itemCount} items` : "Cart"}
   218→              className="relative flex flex-1 items-center gap-3 rounded-lg px-4 py-3 text-bone transition-colors duration-150 hover:bg-moss-green/20 hover:text-amber"
   219→            >
