   224→                    aria-hidden="true"
   225→                    className="absolute -right-1 -top-1 h-2 w-2 rounded-full bg-moss-green"
   226→                  />
   227→                )}
   228→              </span>
   229→              <span className="font-body text-sm">Cart</span>
