              </svg>
              <span className="sr-only">Facebook</span>
            </a>

            {/* Search */}
            <button
              ref={searchButtonRef}
              type="button"
              onClick={toggleSearch}
              aria-label="Search"
              aria-expanded={searchOpen}
              aria-controls="search-panel"
              className="rounded-full p-2 text-bone transition-colors duration-150 hover:bg-moss-green/20 hover:text-amber"
            >
              <Search size={18} aria-hidden="true" />
            </button>

            {/* Account */}
            <div className="relative">
              <button
                ref={accountButtonRef}
                type="button"
                onClick={
                  isAuthenticated
                    ? () => setAccountDropdownOpen((v) => !v)
                    : openAuthModal
