                className="rounded-full p-2 text-bone transition-colors duration-150 hover:bg-moss-green/20 hover:text-amber focus:outline-none focus-visible:outline-2 focus-visible:outline-kombu-green focus-visible:outline-offset-2"
              >
                {isAuthenticated && user ? (
                  <span
                    aria-hidden="true"
                    className="flex h-[22px] w-[22px] items-center justify-center rounded-full bg-amber font-body text-xs font-semibold text-cafe-noir"
                  >
                    {user.initials}
                  </span>
                ) : (
                  <User size={18} aria-hidden="true" />
                )}
              </button>

              {isAuthenticated && accountDropdownOpen && (
                <div className="absolute right-0 top-full mt-2 w-52 rounded-[12px] border border-amber/25 bg-bone/95 p-3 shadow-[0_8px_32px_rgba(74,55,40,0.15)] backdrop-blur-[20px]">
                  <p className="mb-2 px-1 font-body text-xs font-medium text-cafe-noir/60">
                    Welcome back, {user?.name}
                  </p>
                  <button
                    type="button"
                    onClick={() => {
                      signOut();
                      setAccountDropdownOpen(false);
                    }}
                    className="w-full rounded-[8px] px-3 py-2 text-left font-body text-sm text-cafe-noir transition-colors duration-150 hover:bg-amber/20"
                  >
                    Sign Out
                  </button>
                </div>
              )}
            </div>

            {/* Cart */}
            <CartPreview />

            {/* Hamburger — mobile only */}
            <button
              ref={hamburgerRef}
              type="button"
              onClick={() => setMobileMenuOpen(true)}
              aria-label="Open navigation menu"
              aria-expanded={mobileMenuOpen}
              aria-controls="mobile-menu"
              className="ml-1 rounded-full p-2 text-bone transition-colors duration-150 hover:bg-moss-green/20 hover:text-amber lg:hidden"
            >
              <Menu size={18} aria-hidden="true" />
            </button>
          </div>
        </div>
      </header>

      <SearchPanel searchButtonRef={searchButtonRef} />
      <AuthModal accountButtonRef={accountButtonRef} />

      <MobileMenu
        isOpen={mobileMenuOpen}
        onClose={() => setMobileMenuOpen(false)}
        returnFocusRef={hamburgerRef}
      />
    </>
  );
}

