"use client";

import { Search, ShoppingCart, User, X } from "lucide-react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { type RefObject, useEffect, useRef } from "react";
import { useCartStore } from "@/store/cartStore";
import { useUiStore } from "@/store/uiStore";

const navLinks = [
  { label: "Home", href: "/" },
  { label: "Shop", href: "/shop" },
  { label: "Wholesale", href: "/wholesale" },
  { label: "Gallery", href: "/gallery" },
  { label: "Our Story", href: "/#our-story" },
  { label: "Find Us", href: "/#find-us" },
  { label: "News", href: "/news" },
  { label: "Contact", href: "/contact" },
];

interface MobileMenuProps {
  isOpen: boolean;
  onClose: () => void;
  returnFocusRef?: RefObject<HTMLButtonElement | null>;
}

export function MobileMenu({
  isOpen,
  onClose,
  returnFocusRef,
}: MobileMenuProps) {
  const pathname = usePathname();
  const closeButtonRef = useRef<HTMLButtonElement>(null);
  const panelRef = useRef<HTMLDivElement>(null);

  const toggleSearch = useUiStore((s) => s.toggleSearch);
  const openAuthModal = useUiStore((s) => s.openAuthModal);
  const itemCount = useCartStore((s) => s.itemCount);

  // Stable ref so the route-change effect doesn't need onClose in its dep array
  const onCloseRef = useRef(onClose);
  useEffect(() => {
    onCloseRef.current = onClose;
  }, [onClose]);

  // Close on route change — pathname is the intentional trigger
  // biome-ignore lint/correctness/useExhaustiveDependencies: onClose is accessed via stable ref
  useEffect(() => {
    onCloseRef.current();
  }, [pathname]);

  // Focus close button when opened; restore focus to hamburger when closed
  useEffect(() => {
    if (isOpen) {
      closeButtonRef.current?.focus();
    } else {
      returnFocusRef?.current?.focus();
    }
  }, [isOpen, returnFocusRef]);

  // Escape key to close
  useEffect(() => {
    if (!isOpen) return;

    function handleKeyDown(e: KeyboardEvent) {
      if (e.key === "Escape") onClose();
    }

    document.addEventListener("keydown", handleKeyDown);
    return () => document.removeEventListener("keydown", handleKeyDown);
  }, [isOpen, onClose]);

  // Trap focus inside panel
  useEffect(() => {
    if (!isOpen || !panelRef.current) return;

    const panel = panelRef.current;
    const focusable = panel.querySelectorAll<HTMLElement>(
      'a[href], button:not([disabled]), [tabindex]:not([tabindex="-1"])',
    );
    const first = focusable[0];
    const last = focusable[focusable.length - 1];

    function handleTab(e: KeyboardEvent) {
      if (e.key !== "Tab") return;
      if (e.shiftKey) {
        if (document.activeElement === first) {
          e.preventDefault();
          last?.focus();
        }
      } else {
        if (document.activeElement === last) {
          e.preventDefault();
          first?.focus();
        }
      }
    }

    document.addEventListener("keydown", handleTab);
    return () => document.removeEventListener("keydown", handleTab);
  }, [isOpen]);

  // Prevent body scroll when open
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "";
    }
    return () => {
      document.body.style.overflow = "";
    };
  }, [isOpen]);

  function handleSearchClick() {
    toggleSearch();
    onClose();
  }

  function handleAccountClick() {
    openAuthModal();
    onClose();
  }

  return (
    <>
      {/* Backdrop */}
      <div
        aria-hidden="true"
        className={[
          "fixed inset-0 z-40 bg-kombu-green/60 backdrop-blur-sm transition-opacity duration-300",
          isOpen ? "opacity-100" : "pointer-events-none opacity-0",
        ].join(" ")}
        onClick={onClose}
      />

      {/* Panel */}
      <div
        ref={panelRef}
        role="dialog"
        aria-modal="true"
        aria-label="Navigation menu"
        inert={!isOpen}
        className={[
          "fixed inset-0 z-50 flex flex-col bg-kombu-green/95 backdrop-blur-[24px] backdrop-saturate-[200%] transition-all duration-300",
          isOpen
            ? "translate-y-0 opacity-100"
            : "-translate-y-4 opacity-0 pointer-events-none",
        ].join(" ")}
      >
        {/* Header */}
        <div className="flex items-center justify-between border-b border-moss-green/20 px-6 py-5">
          <Link
            href="/"
            onClick={onClose}
            className="font-heading text-xl font-semibold text-bone"
          >
            Riverine Ranch
          </Link>
          <button
            ref={closeButtonRef}
            type="button"
            onClick={onClose}
            aria-label="Close navigation menu"
            className="rounded-full p-2 text-bone transition-colors duration-150 hover:bg-moss-green/20 hover:text-amber"
          >
            <X size={22} aria-hidden="true" />
          </button>
        </div>

        {/* Nav links */}
        <nav
          aria-label="Mobile primary navigation"
          className="flex-1 overflow-y-auto px-6 py-8"
        >
          <ul className="flex flex-col gap-1">
            {navLinks.map(({ label, href }) => (
              <li key={href}>
                <Link
                  href={href}
                  onClick={onClose}
                  className="block rounded-lg px-4 py-3 font-body text-lg font-medium text-bone transition-colors duration-150 hover:bg-moss-green/20 hover:text-amber"
                >
                  {label}
                </Link>
              </li>
            ))}
          </ul>
        </nav>

        {/* Action row */}
        <div className="border-t border-moss-green/20 px-6 py-6">
          <div className="flex items-center gap-3">
            <button
              type="button"
              onClick={handleSearchClick}
              aria-label="Search"
              className="flex flex-1 items-center gap-3 rounded-lg px-4 py-3 text-bone transition-colors duration-150 hover:bg-moss-green/20 hover:text-amber"
            >
              <Search size={22} />
              <span className="font-body text-sm">Search</span>
            </button>

            <button
              type="button"
              onClick={handleAccountClick}
              aria-label="Account"
              className="flex flex-1 items-center gap-3 rounded-lg px-4 py-3 text-bone transition-colors duration-150 hover:bg-moss-green/20 hover:text-amber"
            >
              <User size={22} />
              <span className="font-body text-sm">Account</span>
            </button>

            <Link
              href="/cart"
              onClick={onClose}
              aria-label={itemCount > 0 ? `Cart, ${itemCount} items` : "Cart"}
              className="relative flex flex-1 items-center gap-3 rounded-lg px-4 py-3 text-bone transition-colors duration-150 hover:bg-moss-green/20 hover:text-amber"
            >
              <span className="relative inline-flex">
                <ShoppingCart size={22} />
                {itemCount > 0 && (
                  <span
                    aria-hidden="true"
                    className="absolute -right-1 -top-1 h-2 w-2 rounded-full bg-moss-green"
                  />
                )}
              </span>
              <span className="font-body text-sm">Cart</span>
            </Link>
          </div>
        </div>
      </div>
    </>
  );
}

