   543→function FaqAccordion() {
   544→  const [openQuestion, setOpenQuestion] = useState<string | null>(null);
   545→
   546→  function toggle(question: string) {
   547→    setOpenQuestion((prev) => (prev === question ? null : question));
   548→  }
   549→
   550→  return (
   551→    <div className="space-y-3">
   552→      {faqItems.map((item, index) => {
   553→        const isOpen = openQuestion === item.question;
   554→        const panelId = `faq-panel-${index}`;
   555→        return (
   556→          <div
   557→            key={item.question}
   558→            className="overflow-hidden rounded-[16px] border border-amber/20 bg-white/70 shadow-sm"
   559→          >
   560→            <button
   561→              type="button"
   562→              onClick={() => toggle(item.question)}
   563→              aria-expanded={isOpen}
   564→              aria-controls={panelId}
   565→              className="flex w-full items-center justify-between px-6 py-4 text-left"
   566→            >
   567→              <span className="font-body text-base font-medium text-cafe-noir">
   568→                {item.question}
   569→              </span>
   570→              {isOpen ? (
   571→                <ChevronUp
   572→                  size={18}
   573→                  className="shrink-0 text-kombu-green"
   574→                  aria-hidden="true"
   575→                />
   576→              ) : (
   577→                <ChevronDown
   578→                  size={18}
   579→                  className="shrink-0 text-kombu-green"
   580→                  aria-hidden="true"
   581→                />
   582→              )}
   583→            </button>
   584→            {isOpen && (
   585→              <section id={panelId} className="px-6 pb-5">
   586→                <p className="font-body text-sm leading-relaxed text-cafe-noir/70">
   587→                  {item.answer}
   588→                </p>
   589→              </section>
   590→            )}
   591→          </div>
   592→        );
   593→      })}
   594→    </div>
   595→  );
   596→}
