"use client";

import {
  CheckCircle,
  ChefHat,
  ChevronDown,
  ChevronUp,
  type LucideIcon,
  Package,
  Store,
  Truck,
} from "lucide-react";
import Image from "next/image";
import Link from "next/link";
import { useState } from "react";
import { products } from "@/data/products";

// ---------------------------------------------------------------------------
// Static data
// ---------------------------------------------------------------------------

const whoWeWorkWith: {
  icon: LucideIcon;
  title: string;
  description: string;
}[] = [
  {
    icon: ChefHat,
    title: "Restaurants and Chefs",
    description:
      "From farm-to-table bistros to fine dining kitchens, we supply restaurants that demand authentic, traceable ingredients.",
  },
  {
    icon: Store,
    title: "Specialty Grocery and Co-ops",
    description:
      "We partner with independent grocery stores and food co-ops committed to stocking locally sourced, artisan products.",
  },
  {
    icon: Package,
    title: "Cheese Shops and Fromageries",
    description:
      "Our aged wheels and fresh cheeses are a natural fit for specialty cheese counters and fromageries.",
  },
  {
    icon: Truck,
    title: "Food Distributors",
    description:
      "We work with select regional distributors to expand access to Riverine Ranch products across the tri-state area.",
  },
];

const catalogData: {
  name: string;
  unitSize: string;
  minOrder: string;
  notes: string;
}[] = [
  {
    name: "Buffalo Mozzarella",
    unitSize: "1 lb ball",
    minOrder: "10 lbs/week",
    notes: "Fresh, 7-day shelf life",
  },
  {
    name: "Labneh",
    unitSize: "16 oz tub",
    minOrder: "12 tubs/week",
    notes: "14-day shelf life",
  },
  {
    name: "Buffalo Yogurt",
    unitSize: "32 oz tub",
    minOrder: "12 tubs/week",
    notes: "Plain whole milk, probiotic-rich",
  },
  {
    name: "Farmstead Aged",
    unitSize: "Whole wheel (~500g)",
    minOrder: "6 wheels",
    notes: "Aged on-farm, 30-day shelf life",
  },
  {
    name: "Buffalo Brie",
    unitSize: "Whole wheel (~300g)",
    minOrder: "6 wheels",
    notes: "Bloomy rind, 21-day shelf life",
  },
  {
    name: "Kefir",
    unitSize: "32 oz bottle",
    minOrder: "12 bottles/week",
    notes: "Plain",
  },
  {
    name: "Buffalo Paneer",
    unitSize: "1 lb block",
    minOrder: "10 lbs/week",
    notes: "Ideal for cooking",
  },
  {
    name: "Jerky",
    unitSize: "4 oz bag",
    minOrder: "24 bags/week",
    notes: "Vacuum-sealed, 60-day shelf life",
  },
  {
    name: "4-Pack Burgers",
    unitSize: "4-pack (1.3 lbs)",
    minOrder: "20 packs/week",
    notes: "Frozen available",
  },
  {
    name: "Sweet Sausages",
    unitSize: "1 lb pack",
    minOrder: "15 packs/week",
    notes: "Fresh or frozen",
  },
  {
    name: "Hot Sausage",
    unitSize: "1 lb pack",
    minOrder: "15 packs/week",
    notes: "Fresh or frozen",
  },
  {
    name: "Stew Meat",
    unitSize: "2 lb pack",
    minOrder: "15 packs/week",
    notes: "Vacuum-sealed",
  },
  {
    name: "Mango Lassi",
    unitSize: "16 oz bottle",
    minOrder: "24 bottles/week",
    notes: "Seasonal, refrigerated",
  },
  {
    name: "Passionfruit Yogurt",
    unitSize: "16 oz tub",
    minOrder: "12 tubs/week",
    notes: "Seasonal",
  },
];

const howItWorks = [
  {
    step: "01",
    title: "Apply for a Wholesale Account",
    description:
      "Fill out the inquiry form below with details about your business and what products you are interested in. We review every application personally.",
  },
  {
    step: "02",
    title: "Get Your Custom Price List",
    description:
      "Once approved, we will send you our wholesale pricing sheet with volume tiers, seasonal availability, and delivery schedules.",
  },
  {
    step: "03",
    title: "Schedule Your First Order",
    description:
      "We work with you to align your first order with our production calendar. Weekly and bi-weekly recurring orders are available.",
  },
];

const faqItems = [
  {
    question: "Do you deliver?",
    answer:
      "Yes. We deliver to Manhattan and parts of NJ on a scheduled basis. Pickup at our farm store in Asbury, NJ is also available.",
  },
  {
    question: "What are your payment terms?",
    answer:
      "Net-15 invoicing for established accounts. First orders require prepayment.",
  },
  {
    question: "Is your product certified organic?",
    answer:
      "We are not certified organic, but we do not use antibiotics, growth hormones, GMO feed, or synthetic chemicals. Our practices align with organic principles.",
  },
  {
    question: "Can we get samples before committing?",
    answer:
      "Yes. Approved wholesale applicants can request a sample box at cost before placing their first order.",
  },
  {
    question: "How far in advance do we need to order?",
    answer:
      "We ask for 5 to 7 days lead time for weekly orders. Custom or large orders may require more notice based on our production schedule.",
  },
  {
    question: "Are your products available year-round?",
    answer:
      "Core dairy products are available most of the year. Some items like lassi and passionfruit yogurt are seasonal. We communicate availability changes in advance.",
  },
];

// ---------------------------------------------------------------------------
// Client components
// ---------------------------------------------------------------------------

interface FormState {
  businessName: string;
  contactName: string;
  email: string;
  phone: string;
  businessType: string;
  city: string;
  productsOfInterest: string[];
  estimatedVolume: string;
  message: string;
}

interface FormErrors {
  businessName?: string;
  contactName?: string;
  email?: string;
  businessType?: string;
}

function WholesaleForm() {
  const [form, setForm] = useState<FormState>({
    businessName: "",
    contactName: "",
    email: "",
    phone: "",
    businessType: "",
    city: "",
    productsOfInterest: [],
    estimatedVolume: "",
    message: "",
  });
  const [errors, setErrors] = useState<FormErrors>({});
  const [submitted, setSubmitted] = useState(false);

  const productNames = products.map((p) => p.name);

  function validate(): FormErrors {
    const errs: FormErrors = {};
    if (!form.businessName.trim())
      errs.businessName = "Business name is required.";
    if (!form.contactName.trim())
      errs.contactName = "Contact name is required.";
    if (!form.email.trim()) {
      errs.email = "Email is required.";
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) {
      errs.email = "Please enter a valid email address.";
    }
    if (!form.businessType)
      errs.businessType = "Please select a business type.";
    return errs;
  }

  function handleFieldChange(field: keyof FormErrors) {
    setErrors((prev) => ({ ...prev, [field]: undefined }));
  }

  function handleBlur(field: keyof FormErrors) {
    const errs = validate();
    setErrors((prev) => ({ ...prev, [field]: errs[field] }));
  }

  function handleSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length > 0) {
      setErrors(errs);
      return;
    }
    // TODO: wire to wholesale inquiry API (e.g. internal endpoint or email service)
    setSubmitted(true);
  }

  function toggleProduct(name: string) {
    setForm((prev) => ({
      ...prev,
      productsOfInterest: prev.productsOfInterest.includes(name)
        ? prev.productsOfInterest.filter((p) => p !== name)
        : [...prev.productsOfInterest, name],
    }));
  }

  if (submitted) {
    return (
      <div
        role="status"
        className="flex flex-col items-center justify-center rounded-[16px] border border-amber/20 bg-white/70 p-12 text-center shadow-sm"
      >
        <CheckCircle
          size={48}
          className="mb-4 text-kombu-green"
          aria-hidden="true"
        />
        <h3 className="mb-2 font-heading text-2xl font-semibold text-cafe-noir">
          Inquiry Received
        </h3>
        <p className="font-body text-base text-cafe-noir/70">
          Thank you for reaching out. We will review your application and get
          back to you within 2 business days at{" "}
          <span className="text-kombu-green">{form.email}</span>.
        </p>
      </div>
    );
  }

  const inputClass =
    "w-full rounded-[8px] border border-amber/40 bg-white px-4 py-3 font-body text-sm text-cafe-noir outline-none focus:border-kombu-green";
  const labelClass =
    "mb-1 block font-body text-sm font-medium text-cafe-noir/80";
  const errorClass = "mt-1 font-body text-xs text-red-600";

  return (
    <form
      onSubmit={handleSubmit}
      noValidate
      className="rounded-[16px] border border-amber/20 bg-white/70 p-8 shadow-sm"
    >
      <div className="grid gap-5 sm:grid-cols-2">
        {/* Business Name */}
        <div>
          <label htmlFor="businessName" className={labelClass}>
            Business Name <span aria-hidden="true">*</span>
          </label>
          <input
            id="businessName"
            type="text"
            required
            value={form.businessName}
            onChange={(e) => {
              setForm((p) => ({ ...p, businessName: e.target.value }));
              handleFieldChange("businessName");
            }}
            onBlur={() => handleBlur("businessName")}
            className={inputClass}
            aria-required="true"
            aria-invalid={!!errors.businessName}
            aria-describedby={
              errors.businessName ? "businessName-error" : undefined
            }
          />
          {errors.businessName && (
            <p id="businessName-error" className={errorClass} role="alert">
              {errors.businessName}
            </p>
          )}
        </div>

        {/* Contact Name */}
        <div>
          <label htmlFor="contactName" className={labelClass}>
            Contact Name <span aria-hidden="true">*</span>
          </label>
          <input
            id="contactName"
            type="text"
            required
            value={form.contactName}
            onChange={(e) => {
              setForm((p) => ({ ...p, contactName: e.target.value }));
              handleFieldChange("contactName");
            }}
            onBlur={() => handleBlur("contactName")}
            className={inputClass}
            aria-required="true"
            aria-invalid={!!errors.contactName}
            aria-describedby={
              errors.contactName ? "contactName-error" : undefined
            }
          />
          {errors.contactName && (
            <p id="contactName-error" className={errorClass} role="alert">
              {errors.contactName}
            </p>
          )}
        </div>

        {/* Email */}
        <div>
          <label htmlFor="email" className={labelClass}>
            Email <span aria-hidden="true">*</span>
          </label>
          <input
            id="email"
            type="email"
            required
            value={form.email}
            onChange={(e) => {
              setForm((p) => ({ ...p, email: e.target.value }));
              handleFieldChange("email");
            }}
            onBlur={() => handleBlur("email")}
            className={inputClass}
            aria-required="true"
            aria-invalid={!!errors.email}
            aria-describedby={errors.email ? "email-error" : undefined}
          />
          {errors.email && (
            <p id="email-error" className={errorClass} role="alert">
              {errors.email}
            </p>
          )}
        </div>

        {/* Phone */}
        <div>
          <label htmlFor="phone" className={labelClass}>
            Phone
          </label>
          <input
            id="phone"
            type="tel"
            value={form.phone}
            onChange={(e) => setForm((p) => ({ ...p, phone: e.target.value }))}
            className={inputClass}
          />
        </div>

        {/* Business Type */}
        <div>
          <label htmlFor="businessType" className={labelClass}>
            Business Type <span aria-hidden="true">*</span>
          </label>
          <select
            id="businessType"
            required
            value={form.businessType}
            onChange={(e) => {
              setForm((p) => ({ ...p, businessType: e.target.value }));
              handleFieldChange("businessType");
            }}
            onBlur={() => handleBlur("businessType")}
            className={inputClass}
            aria-required="true"
            aria-invalid={!!errors.businessType}
            aria-describedby={
              errors.businessType ? "businessType-error" : undefined
            }
          >
            <option value="">Select a type</option>
            <option value="Restaurant">Restaurant</option>
            <option value="Specialty Grocery">Specialty Grocery</option>
            <option value="Cheese Shop">Cheese Shop</option>
            <option value="Food Distributor">Food Distributor</option>
            <option value="Other">Other</option>
          </select>
          {errors.businessType && (
            <p id="businessType-error" className={errorClass} role="alert">
              {errors.businessType}
            </p>
          )}
        </div>

        {/* City */}
        <div>
          <label htmlFor="city" className={labelClass}>
            Location / City
          </label>
          <input
            id="city"
            type="text"
            value={form.city}
            onChange={(e) => setForm((p) => ({ ...p, city: e.target.value }))}
            className={inputClass}
          />
        </div>

        {/* Estimated Weekly Volume */}
        <div className="sm:col-span-2">
          <label htmlFor="estimatedVolume" className={labelClass}>
            Estimated Weekly Volume
          </label>
          <select
            id="estimatedVolume"
            value={form.estimatedVolume}
            onChange={(e) =>
              setForm((p) => ({ ...p, estimatedVolume: e.target.value }))
            }
            className={inputClass}
          >
            <option value="">Select a range</option>
            <option value="Under $500">Under $500/week</option>
            <option value="$500 - $1,000">$500 - $1,000/week</option>
            <option value="$1,000 - $2,500">$1,000 - $2,500/week</option>
            <option value="$2,500+">$2,500+/week</option>
          </select>
        </div>

        {/* Products of Interest */}
        <div className="sm:col-span-2">
          <p className={labelClass}>Products of Interest</p>
          <div className="mt-2 grid grid-cols-2 gap-2 sm:grid-cols-3 lg:grid-cols-4">
            {productNames.map((name) => (
              <label
                key={name}
                className="flex cursor-pointer items-center gap-2 font-body text-sm text-cafe-noir/75"
              >
                <input
                  type="checkbox"
                  checked={form.productsOfInterest.includes(name)}
                  onChange={() => toggleProduct(name)}
                  className="h-4 w-4 accent-kombu-green"
                />
                {name}
              </label>
            ))}
          </div>
        </div>

        {/* Message */}
        <div className="sm:col-span-2">
          <label htmlFor="message" className={labelClass}>
            Tell us about your business
          </label>
          <textarea
            id="message"
            rows={4}
            value={form.message}
            onChange={(e) =>
              setForm((p) => ({ ...p, message: e.target.value }))
            }
            className={inputClass}
            placeholder="Share details about your business, order frequency, and any specific needs."
          />
        </div>
      </div>

      <div className="mt-6">
        <button
          type="submit"
          className="inline-flex items-center justify-center rounded-[12px] bg-kombu-green px-8 py-3 font-body text-sm font-medium text-bone transition-colors duration-200 hover:bg-kombu-green/85"
        >
          Submit Inquiry
        </button>
        <p className="mt-3 font-body text-xs text-cafe-noir/50">
          Fields marked with * are required.
        </p>
      </div>
    </form>
  );
}

function FaqAccordion() {
  const [openQuestion, setOpenQuestion] = useState<string | null>(null);

  function toggle(question: string) {
    setOpenQuestion((prev) => (prev === question ? null : question));
  }

  return (
    <div className="space-y-3">
      {faqItems.map((item, index) => {
        const isOpen = openQuestion === item.question;
        const panelId = `faq-panel-${index}`;
        return (
          <div
            key={item.question}
            className="overflow-hidden rounded-[16px] border border-amber/20 bg-white/70 shadow-sm"
          >
            <button
              type="button"
              onClick={() => toggle(item.question)}
              aria-expanded={isOpen}
              aria-controls={panelId}
              className="flex w-full items-center justify-between px-6 py-4 text-left"
            >
              <span className="font-body text-base font-medium text-cafe-noir">
                {item.question}
              </span>
              {isOpen ? (
                <ChevronUp
                  size={18}
                  className="shrink-0 text-kombu-green"
                  aria-hidden="true"
                />
              ) : (
                <ChevronDown
                  size={18}
                  className="shrink-0 text-kombu-green"
                  aria-hidden="true"
                />
              )}
            </button>
            {isOpen && (
              <section id={panelId} className="px-6 pb-5">
                <p className="font-body text-sm leading-relaxed text-cafe-noir/70">
                  {item.answer}
                </p>
              </section>
            )}
          </div>
        );
      })}
    </div>
  );
}

