import type { Metadata } from "next";
import { Inter, Playfair_Display } from "next/font/google";
import { Footer } from "@/components/layout/Footer";
import { Navbar } from "@/components/nav/Navbar";
import { env } from "@/lib/env";
import "./globals.css";

const playfairDisplay = Playfair_Display({
  subsets: ["latin"],
  variable: "--font-playfair-display",
  display: "swap",
});

const inter = Inter({
  subsets: ["latin"],
  variable: "--font-inter",
  display: "swap",
});

export const metadata: Metadata = {
  metadataBase: new URL(env.NEXT_PUBLIC_APP_URL ?? "https://riverineranch.com"),
  title: {
    default: "Riverine Ranch | Artisan Water Buffalo Dairy and Meat",
    template: "%s | Riverine Ranch",
  },
  description:
    "Family-owned water buffalo farm in Asbury, NJ. Artisan dairy and meat products, raised on grass, rooted in tradition.",
  icons: {
    icon: "/favicon.ico",
  },
  openGraph: {
    siteName: "Riverine Ranch",
    // TODO: add a 1200x630 og-image.jpg to public/
    images: ["/og-image.jpg"],
  },
};

export default function RootLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <html
      lang="en"
      data-scroll-behavior="smooth"
      className={`${playfairDisplay.variable} ${inter.variable}`}
    >
      <body>
        <a href="#main-content" className="skip-to-content">
          Skip to content
        </a>
        <Navbar />
        <main id="main-content">{children}</main>
        <Footer />
      </body>
    </html>
  );
}

