"use client";

import { motion } from "framer-motion";
import { MapPin, Menu, Search, User } from "lucide-react";
import Image from "next/image";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { useEffect, useRef, useState } from "react";
import { useAuthStore } from "@/store/authStore";
import { useUiStore } from "@/store/uiStore";
import { AuthModal } from "./AuthModal";
import { CartPreview } from "./CartPreview";
import { MobileMenu } from "./MobileMenu";
import { SearchPanel } from "./SearchPanel";

const navLinks = [
  { label: "Home", href: "/" },
  { label: "Shop", href: "/shop" },
  { label: "Wholesale", href: "/wholesale" },
  { label: "Gallery", href: "/gallery" },
  { label: "News", href: "/news" },
  { label: "Contact", href: "/contact" },
];

export function Navbar() {
  const pathname = usePathname();
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [accountDropdownOpen, setAccountDropdownOpen] = useState(false);
  const hamburgerRef = useRef<HTMLButtonElement>(null);

  const searchButtonRef = useRef<HTMLButtonElement>(null);
  const accountButtonRef = useRef<HTMLButtonElement>(null);

  const toggleSearch = useUiStore((s) => s.toggleSearch);
  const searchOpen = useUiStore((s) => s.searchOpen);
  const openAuthModal = useUiStore((s) => s.openAuthModal);
  const isAuthenticated = useAuthStore((s) => s.isAuthenticated);
  const user = useAuthStore((s) => s.user);
  const signOut = useAuthStore((s) => s.signOut);

  // Close mobile menu on route change — pathname is the intentional trigger
  // biome-ignore lint/correctness/useExhaustiveDependencies: pathname is the intentional dep; setMobileMenuOpen is stable
  useEffect(() => {
    setMobileMenuOpen(false);
  }, [pathname]);

  // Close account dropdown on Escape or outside click
  useEffect(() => {
    if (!accountDropdownOpen) return;

    function handleKeyDown(e: KeyboardEvent) {
      if (e.key === "Escape") setAccountDropdownOpen(false);
    }

    function handleMouseDown(e: MouseEvent) {
      if (!accountButtonRef.current?.contains(e.target as Node)) {
        setAccountDropdownOpen(false);
        accountButtonRef.current?.blur();
      }
    }

    document.addEventListener("keydown", handleKeyDown);
    document.addEventListener("mousedown", handleMouseDown);
    return () => {
      document.removeEventListener("keydown", handleKeyDown);
      document.removeEventListener("mousedown", handleMouseDown);
    };
  }, [accountDropdownOpen]);

  return (
    <>
      <header
        className={[
          "fixed inset-x-0 top-0 z-30 w-full border-b border-moss-green/20 transition-colors duration-300",
          "bg-kombu-green/90 backdrop-blur-[24px] backdrop-saturate-[200%]",
        ].join(" ")}
      >
        <div className="mx-auto flex h-16 max-w-7xl items-center justify-between gap-4 px-6">
          {/* LEFT: Wordmark */}
          <Link
            href="/"
            className="flex flex-1 shrink-0 items-center gap-2 text-bone transition-opacity duration-150 hover:opacity-80"
            aria-label="Riverine Ranch — home"
          >
            <Image
              src="/logo.png"
              alt=""
              width={30}
              height={30}
              aria-hidden="true"
            />
            <span className="font-heading text-lg font-semibold text-bone">
              Riverine Ranch
            </span>
          </Link>

          {/* CENTER: Desktop nav links */}
          <nav
            aria-label="Primary navigation"
            className="hidden lg:flex lg:items-center lg:gap-1"
          >
            {navLinks.map(({ label, href }) => {
              const isActive = pathname === href;
              return (
                <Link
                  key={href}
                  href={href}
                  className={[
                    "relative rounded-md px-3 py-1.5 font-body text-sm transition-colors duration-200",
                    isActive
                      ? "text-amber"
                      : "text-bone/70 hover:bg-white/8 hover:text-bone",
                  ].join(" ")}
                  aria-current={isActive ? "page" : undefined}
                >
                  {label}
                  {isActive && (
                    <motion.span
                      layoutId="nav-underline"
                      className="absolute inset-x-3 bottom-0 h-[2px] rounded-full bg-amber"
                      transition={{
                        type: "spring",
                        stiffness: 380,
                        damping: 30,
                      }}
                    />
                  )}
                </Link>
              );
            })}
          </nav>

          {/* RIGHT: Icon actions */}
          <div className="flex flex-1 items-center justify-end gap-1">
            {/* Find Us */}
            <Link
              href="/#find-us"
              aria-label="Find Us"
              className="rounded-full p-2 text-bone transition-colors duration-150 hover:bg-moss-green/20 hover:text-amber"
            >
              <MapPin size={18} aria-hidden="true" />
            </Link>

            {/* Instagram */}
            <a
              href="https://www.instagram.com/riverineranch"
              target="_blank"
              rel="noopener noreferrer"
              aria-label="Riverine Ranch on Instagram"
              className="hidden rounded-full p-2 text-bone transition-colors duration-150 hover:bg-moss-green/20 hover:text-amber sm:block"
            >
              <svg
                width="18"
                height="18"
                viewBox="0 0 24 24"
                fill="currentColor"
                aria-hidden="true"
              >
                <path d="M12 2.163c3.204 0 3.584.012 4.85.07 3.252.148 4.771 1.691 4.919 4.919.058 1.265.069 1.645.069 4.849 0 3.205-.012 3.584-.069 4.849-.149 3.225-1.664 4.771-4.919 4.919-1.266.058-1.644.07-4.85.07-3.204 0-3.584-.012-4.849-.07-3.26-.149-4.771-1.699-4.919-4.92-.058-1.265-.07-1.644-.07-4.849 0-3.204.013-3.583.07-4.849.149-3.227 1.664-4.771 4.919-4.919 1.266-.057 1.645-.069 4.849-.069zM12 0C8.741 0 8.333.014 7.053.072 2.695.272.273 2.69.073 7.052.014 8.333 0 8.741 0 12s.014 3.668.072 4.948c.2 4.358 2.618 6.78 6.98 6.98C8.333 23.986 8.741 24 12 24s3.668-.014 4.948-.072c4.354-.2 6.782-2.618 6.979-6.98.059-1.28.073-1.689.073-4.948s-.014-3.667-.072-4.947c-.196-4.354-2.617-6.78-6.979-6.98C15.668.014 15.259 0 12 0zm0 5.838a6.162 6.162 0 100 12.324 6.162 6.162 0 000-12.324zM12 16a4 4 0 110-8 4 4 0 010 8zm6.406-11.845a1.44 1.44 0 100 2.881 1.44 1.44 0 000-2.881z" />
              </svg>
              <span className="sr-only">Instagram</span>
            </a>

            {/* Facebook */}
            <a
              href="https://www.facebook.com/riverineranch"
              target="_blank"
              rel="noopener noreferrer"
              aria-label="Riverine Ranch on Facebook"
              className="hidden rounded-full p-2 text-bone transition-colors duration-150 hover:bg-moss-green/20 hover:text-amber sm:block"
            >
              <svg
                width="18"
                height="18"
                viewBox="0 0 24 24"
                fill="currentColor"
                aria-hidden="true"
              >
                <path d="M24 12.073c0-6.627-5.373-12-12-12s-12 5.373-12 12c0 5.99 4.388 10.954 10.125 11.854v-8.385H7.078v-3.47h3.047V9.43c0-3.007 1.792-4.669 4.533-4.669 1.312 0 2.686.235 2.686.235v2.953H15.83c-1.491 0-1.956.925-1.956 1.874v2.25h3.328l-.532 3.47h-2.796v8.385C19.612 23.027 24 18.062 24 12.073z" />
              </svg>
              <span className="sr-only">Facebook</span>
            </a>

            {/* Search */}
            <button
              ref={searchButtonRef}
              type="button"
              onClick={toggleSearch}
              aria-label="Search"
              aria-expanded={searchOpen}
              aria-controls="search-panel"
              className="rounded-full p-2 text-bone transition-colors duration-150 hover:bg-moss-green/20 hover:text-amber"
            >
              <Search size={18} aria-hidden="true" />
            </button>

            {/* Account */}
            <div className="relative">
              <button
                ref={accountButtonRef}
                type="button"
                onClick={
                  isAuthenticated
                    ? () => setAccountDropdownOpen((v) => !v)
                    : openAuthModal
                }
                aria-label={isAuthenticated ? "Account menu" : "Sign in"}
                aria-expanded={
                  isAuthenticated ? accountDropdownOpen : undefined
                }
                className="rounded-full p-2 text-bone transition-colors duration-150 hover:bg-moss-green/20 hover:text-amber focus:outline-none focus-visible:outline-2 focus-visible:outline-kombu-green focus-visible:outline-offset-2"
              >
                {isAuthenticated && user ? (
                  <span
                    aria-hidden="true"
                    className="flex h-[22px] w-[22px] items-center justify-center rounded-full bg-amber font-body text-xs font-semibold text-cafe-noir"
                  >
                    {user.initials}
                  </span>
                ) : (
                  <User size={18} aria-hidden="true" />
                )}
              </button>

              {isAuthenticated && accountDropdownOpen && (
                <div className="absolute right-0 top-full mt-2 w-52 rounded-[12px] border border-amber/25 bg-bone/95 p-3 shadow-[0_8px_32px_rgba(74,55,40,0.15)] backdrop-blur-[20px]">
                  <p className="mb-2 px-1 font-body text-xs font-medium text-cafe-noir/60">
                    Welcome back, {user?.name}
                  </p>
                  <button
                    type="button"
                    onClick={() => {
                      signOut();
                      setAccountDropdownOpen(false);
                    }}
                    className="w-full rounded-[8px] px-3 py-2 text-left font-body text-sm text-cafe-noir transition-colors duration-150 hover:bg-amber/20"
                  >
                    Sign Out
                  </button>
                </div>
              )}
            </div>

            {/* Cart */}
            <CartPreview />

            {/* Hamburger — mobile only */}
            <button
              ref={hamburgerRef}
              type="button"
              onClick={() => setMobileMenuOpen(true)}
              aria-label="Open navigation menu"
              aria-expanded={mobileMenuOpen}
              aria-controls="mobile-menu"
              className="ml-1 rounded-full p-2 text-bone transition-colors duration-150 hover:bg-moss-green/20 hover:text-amber lg:hidden"
            >
              <Menu size={18} aria-hidden="true" />
            </button>
          </div>
        </div>
      </header>

      <SearchPanel searchButtonRef={searchButtonRef} />
      <AuthModal accountButtonRef={accountButtonRef} />

      <MobileMenu
        isOpen={mobileMenuOpen}
        onClose={() => setMobileMenuOpen(false)}
        returnFocusRef={hamburgerRef}
      />
    </>
  );
}

