import Link from "next/link";
import { FacebookIcon } from "@/components/icons/FacebookIcon";
import { InstagramIcon } from "@/components/icons/InstagramIcon";
import { CONTACT_INFO, FARM, NAV_LINKS, SITE_NAME, SOCIAL } from "@/constants";

const col1Hrefs = ["/", "/shop", "/#our-story", "/gallery"];
const col2Hrefs = ["/wholesale", "/#find-us", "/news", "/contact"];
const navCol1 = NAV_LINKS.filter(({ href }) => col1Hrefs.includes(href));
const navCol2 = NAV_LINKS.filter(({ href }) => col2Hrefs.includes(href));

export function Footer() {
  return (
    <footer className="bg-kombu-green">
      <div className="mx-auto max-w-7xl px-6 py-16">
        <div className="grid grid-cols-1 gap-12 sm:grid-cols-2 lg:grid-cols-4">
          {/* Logo + tagline */}
          <div className="flex flex-col gap-3">
            <span className="font-heading text-2xl font-semibold text-bone">
              {SITE_NAME}
            </span>
            <p className="font-body text-sm leading-relaxed text-bone/70">
              Artisan water buffalo dairy and meat, raised on grass, rooted in
              tradition.
            </p>
          </div>

          {/* Nav column 1 */}
          <nav aria-label="Footer primary navigation">
            <ul className="flex flex-col gap-3">
              {navCol1.map(({ label, href }) => (
                <li key={href}>
                  <Link
                    href={href}
                    className="font-body text-sm text-bone/70 transition-colors duration-150 hover:text-bone"
                  >
                    {label}
                  </Link>
                </li>
              ))}
            </ul>
          </nav>

          {/* Nav column 2 */}
          <nav aria-label="Footer secondary navigation">
            <ul className="flex flex-col gap-3">
              {navCol2.map(({ label, href }) => (
                <li key={href}>
                  <Link
                    href={href}
                    className="font-body text-sm text-bone/70 transition-colors duration-150 hover:text-bone"
                  >
                    {label}
                  </Link>
                </li>
              ))}
            </ul>
