                {FARM.street}
                <br />
                {FARM.city}, {FARM.state} {FARM.zip}
              </p>
              <a
                href={CONTACT_INFO.phoneHref}
                className="mt-2 block font-body text-sm text-bone/70 transition-colors duration-150 hover:text-bone"
              >
                {CONTACT_INFO.phone}
              </a>
              <a
                href={CONTACT_INFO.emailHref}
                className="mt-1 block font-body text-sm text-bone/70 transition-colors duration-150 hover:text-bone"
              >
                {CONTACT_INFO.email}
              </a>
            </address>

            {/* Social links */}
            <div className="mt-1 flex gap-4">
              <a
                href={SOCIAL.instagram.url}
                target="_blank"
                rel="noopener noreferrer"
                aria-label={SOCIAL.instagram.label}
                className="text-bone/70 transition-colors duration-150 hover:text-bone"
              >
                <InstagramIcon size={20} />
                <span className="sr-only">Instagram</span>
              </a>
              <a
                href={SOCIAL.facebook.url}
                target="_blank"
                rel="noopener noreferrer"
                aria-label={SOCIAL.facebook.label}
                className="text-bone/70 transition-colors duration-150 hover:text-bone"
