      {/* Wholesale Inquiry Form */}
      <section className="bg-bone px-6 py-20 lg:py-24">
        <div className="mx-auto max-w-3xl">
          <div className="mb-10 text-center">
            <p className="mb-3 font-body text-sm font-medium uppercase tracking-[0.2em] text-moss-green">
              Get Started
            </p>
            <h2 className="mb-3 font-heading text-3xl font-semibold text-cafe-noir lg:text-4xl">
              Wholesale Inquiry
            </h2>
            <p className="font-body text-sm leading-relaxed text-cafe-noir/65">
              Tell us about your business and we will be in touch within 2
              business days.
            </p>
          </div>
          <WholesaleForm />
        </div>
      </section>

      {/* Social Proof */}
      <section className="bg-bone px-6 py-20 lg:py-24">
        <div className="mx-auto max-w-5xl text-center">
          <p className="mb-3 font-body text-sm font-medium uppercase tracking-[0.2em] text-moss-green">
            Our Partners
          </p>
          <h2 className="mb-6 font-heading text-3xl font-semibold text-cafe-noir lg:text-4xl">
            Trusted by NYC&apos;s Best Tables
          </h2>
          <p className="mx-auto mb-12 max-w-xl font-body text-base leading-relaxed text-cafe-noir/65">
            From celebrated restaurants to neighborhood co-ops, Riverine Ranch
            products are on the menus and shelves of businesses that care about
            where their food comes from.
          </p>
          {/* TODO: replace placeholder partner logos with real partners or remove section */}
          <div className="flex flex-wrap items-center justify-center gap-6">
            <div className="flex h-16 w-44 items-center justify-center rounded-[16px] border border-amber/20 bg-white/70 px-4 shadow-sm">
              <span className="font-heading text-sm font-semibold text-cafe-noir">
                Union Square Cafe
              </span>
            </div>
            <div className="flex h-16 w-44 items-center justify-center rounded-[16px] border border-amber/20 bg-white/70 px-4 shadow-sm">
              <span className="font-body text-xs font-medium uppercase tracking-[0.1em] text-cafe-noir/40">
                Partner Logo
              </span>
            </div>
            <div className="flex h-16 w-44 items-center justify-center rounded-[16px] border border-amber/20 bg-white/70 px-4 shadow-sm">
              <span className="font-body text-xs font-medium uppercase tracking-[0.1em] text-cafe-noir/40">
                Partner Logo
              </span>
            </div>
          </div>
        </div>
      </section>

      {/* FAQ */}
      <section className="bg-bone px-6 pb-28 pt-4">
        <div className="mx-auto max-w-3xl">
          <div className="mb-10 text-center">
            <p className="mb-3 font-body text-sm font-medium uppercase tracking-[0.2em] text-moss-green">
              FAQ
            </p>
            <h2 className="font-heading text-3xl font-semibold text-cafe-noir lg:text-4xl">
              Frequently Asked Questions
            </h2>
          </div>
          <FaqAccordion />
          <div className="mt-10 text-center">
            <p className="mb-4 font-body text-sm text-cafe-noir/60">
              Still have questions? We are happy to help.
            </p>
            <Link
              href="/contact"
              className="inline-flex items-center justify-center rounded-[12px] bg-kombu-green px-6 py-3 font-body text-sm font-medium text-bone transition-colors duration-200 hover:bg-kombu-green/85"
            >
              Contact Us
            </Link>
          </div>
        </div>
      </section>
    </>
  );
}

