"use client";

import { CheckCircle, ChevronDown, ChevronUp } from "lucide-react";
import Image from "next/image";
import Link from "next/link";
import { useState } from "react";
import { SITE_NAME } from "@/constants";
import {
  catalogData,
  faqItems,
  howItWorks,
  whoWeWorkWith,
} from "@/data/wholesale";
